create policy "users insert valid shared links"
on public.shared_links for insert
to authenticated
with check (
  is_active
  and slug = lower(slug)
  and slug ~ '^[a-z0-9][a-z0-9_-]{5,63}$'
  and (
    (
      content_type = 'place'
      and place_id is not null
      and route_id is null
      and exists (
        select 1 from public.places p
        where p.id = shared_links.place_id
          and p.app_status = 'published'
      )
    )
    or (
      content_type = 'route'
      and route_id is not null
      and place_id is null
      and exists (
        select 1
        from public.routes r
        join public.app_users u on u.id = r.app_user_id
        where r.id = shared_links.route_id
          and r.status = 'saved'
          and r.is_public
          and u.auth_user_id = (select auth.uid())
      )
    )
  )
);

create policy "users insert own app events"
on public.app_events for insert
to authenticated
with check (
  event_name ~ '^[a-z0-9][a-z0-9_.:-]{0,119}$'
  and (duration_ms is null or duration_ms >= 0)
  and exists (
    select 1 from public.app_users u
    where u.id = app_events.app_user_id
      and u.auth_user_id = (select auth.uid())
  )
  and (
    session_id is null
    or exists (
      select 1 from public.app_sessions s
      where s.id = app_events.session_id
        and s.app_user_id = app_events.app_user_id
    )
  )
);

